sysauto_script.script:
(function() {
    // Find donors whose next_eligible_date has passed and are still temporarily_ineligible
    var gr = new GlideRecord('x_1920732_lifeli_0_donor_profile');
    gr.addQuery('eligibility_status', 'temporarily_ineligible');
    gr.addQuery('next_eligible_date', '<=', new GlideDateTime().getDate().getValue());
    gr.query();

    var count = 0;
    while (gr.next()) {
        gr.setValue('eligibility_status', 'eligible');
        gr.update();

        // Fire donor eligible event
        gs.eventQueue('x_1920732_lifeli_0.donor.eligible', gr, gr.getValue('user'), gr.getValue('blood_group'));
        count++;
    }
    gs.info('LifeLink: Donor Eligibility Checker restored eligibility for ' + count + ' donors.');
})();
